/*! coi-serviceworker v0.1.7 - Guido Zuidhof, licensed under MIT */
/*
 * This service worker intercepts all fetch requests and adds the required
 * Cross-Origin headers for SharedArrayBuffer support (needed for wa-sqlite OPFS).
 * 
 * On first load, it will register itself and reload the page once.
 * After that, all responses get COOP: same-origin and COEP: require-corp headers.
 */
if(typeof window==='undefined'){
  self.addEventListener("install",()=>self.skipWaiting());
  self.addEventListener("activate",(e)=>e.waitUntil(self.clients.claim()));
  self.addEventListener("message",(e)=>{if(e.data&&e.data.type==="deregister"){self.registration.unregister().then(()=>{e.source.postMessage({type:"deregistered"})})}});
  self.addEventListener("fetch",function(e){if(e.request.cache==="only-if-cached"&&e.request.mode!=="same-origin")return;e.respondWith(fetch(e.request).then(r=>{if(r.status===0)return r;const headers=new Headers(r.headers);headers.set("Cross-Origin-Embedder-Policy","require-corp");headers.set("Cross-Origin-Opener-Policy","same-origin");return new Response(r.body,{status:r.status,statusText:r.statusText,headers})}).catch(e=>console.error(e)))});
}else{
  (async()=>{
    const r=window.isSecureContext;
    if(!r){console.warn("coi-serviceworker: not in secure context");return}
    if(window.crossOriginIsolated!==false)return;
    const reg=await navigator.serviceWorker.register(window.document.currentScript.src).catch(e=>{console.error("coi-serviceworker registration failed:",e)});
    if(reg){
      console.log("coi-serviceworker: registered, reloading page for COOP/COEP headers...");
      window.sessionStorage.setItem("coi-reloaded","true");
      window.location.reload();
    }
  })();
}
